import React, { useState } from 'react';
import axios from 'axios';

function App() {
  // These are memory slots for our app
  const [selectedFile, setSelectedFile] = useState(null);
  const [signature, setSignature] = useState('');
  const [status, setStatus] = useState('idle'); // idle, loading, success, error
  const [message, setMessage] = useState('');
  const [verifyFile, setVerifyFile] = useState(null);
  const [verifySignatureInput, setVerifySignatureInput] = useState('');

  // ----- FUNCTION 1: Upload & Sign -----
  const handleUpload = async () => {
    if (!selectedFile) {
      alert('Please select a file first!');
      return;
    }

    setStatus('loading');
    setMessage('📤 Sending file to backend for signing...');

    const formData = new FormData();
    formData.append('file', selectedFile);

    try {
      const response = await axios.post(
        'http://localhost:8080/api/documents/upload',
        formData,
        { headers: { 'Content-Type': 'multipart/form-data' } }
      );

      // IMPORTANT: Ask Member 3 to make sure their backend returns { signature: "...." }
      const returnedSignature = response.data.signature;
      setSignature(returnedSignature);
      setStatus('success');
      setMessage('✅ File signed successfully! Copy the signature or download it below.');
    } catch (error) {
      setStatus('error');
      setMessage('❌ Upload failed. Is the backend server running on port 8080?');
      console.error(error);
    }
  };

  // ----- FUNCTION 2: Verify a file -----
  const handleVerify = async () => {
    if (!verifyFile || !verifySignatureInput) {
      alert('Please pick a file AND paste the signature string!');
      return;
    }

    setStatus('loading');
    setMessage('🔍 Checking file authenticity...');

    const formData = new FormData();
    formData.append('file', verifyFile);
    formData.append('signature', verifySignatureInput);

    try {
      const response = await axios.post(
        'http://localhost:8080/api/documents/verify',
        formData,
        { headers: { 'Content-Type': 'multipart/form-data' } }
      );

      if (response.data.valid === true) {
        setStatus('success');
        setMessage('✅ GREAT! The file is 100% AUTHENTIC (Green badge).');
      } else {
        setStatus('error');
        setMessage('❌ TAMPERED! The file does not match the signature (Red banner).');
      }
    } catch (error) {
      setStatus('error');
      setMessage('❌ Verification failed. Backend error.');
      console.error(error);
    }
  };

  // ----- FUNCTION 3: Download Signature as .txt -----
  const downloadSignature = () => {
    const blob = new Blob([signature], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'my_digital_signature.txt';
    link.click();
    URL.revokeObjectURL(url);
  };

  // ----- THE ACTUAL SCREEN (HTML/CSS inside React) -----
  return (
    <div style={{ fontFamily: 'Arial', maxWidth: '800px', margin: '0 auto', padding: '20px' }}>
      <h1 style={{ color: '#1a73e8' }}>📄 DigiSign Dashboard</h1>

      {/* ---------- SECTION 1: UPLOAD & SIGN ---------- */}
      <div style={{ border: '1px solid #ccc', padding: '20px', borderRadius: '10px', marginBottom: '30px' }}>
        <h2>Step 1: Upload & Sign a File</h2>
        <input 
          type="file" 
          onChange={(e) => setSelectedFile(e.target.files[0])} 
        />
        <button 
          onClick={handleUpload} 
          style={{ marginLeft: '10px', padding: '10px 20px', backgroundColor: '#1a73e8', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
        >
          🚀 Sign File
        </button>

        {signature && (
          <div style={{ marginTop: '15px', background: '#f0f0f0', padding: '10px', borderRadius: '5px' }}>
            <strong>Generated Signature:</strong>
            <p style={{ wordBreak: 'break-all', fontSize: '12px' }}>{signature}</p>
            <button onClick={downloadSignature} style={{ padding: '5px 15px', backgroundColor: '#28a745', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>
              ⬇️ Download .txt
            </button>
          </div>
        )}
      </div>

      {/* ---------- SECTION 2: VERIFY FILE ---------- */}
      <div style={{ border: '1px solid #ccc', padding: '20px', borderRadius: '10px', marginBottom: '30px' }}>
        <h2>Step 2: Verify a File</h2>
        <p>Pick the file again, and paste the signature string:</p>
        <input 
          type="file" 
          onChange={(e) => setVerifyFile(e.target.files[0])} 
        />
        <br /><br />
        <textarea 
          placeholder="Paste the signature string here..." 
          rows="2" 
          style={{ width: '90%', padding: '10px' }}
          onChange={(e) => setVerifySignatureInput(e.target.value)}
        ></textarea>
        <br /><br />
        <button 
          onClick={handleVerify} 
          style={{ padding: '10px 20px', backgroundColor: '#ffc107', color: 'black', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
        >
          🔎 Verify File
        </button>
      </div>

      {/* ---------- STATUS DISPLAY (Green / Red / Loading) ---------- */}
      <div style={{ marginTop: '20px', padding: '15px', borderRadius: '8px', border: '1px solid #ddd' }}>
        <h3>Status:</h3>

        {status === 'loading' && (
          <div style={{ color: '#007bff' }}>
            <span>⏳ {message} (Please wait...)</span>
          </div>
        )}

        {status === 'success' && (
          <div style={{ backgroundColor: '#d4edda', color: '#155724', padding: '15px', borderRadius: '5px', border: '1px solid #c3e6cb' }}>
            <span>✅ {message}</span>
          </div>
        )}

        {status === 'error' && (
          <div style={{ backgroundColor: '#f8d7da', color: '#721c24', padding: '15px', borderRadius: '5px', border: '1px solid #f5c6cb' }}>
            <span>❌ {message}</span>
          </div>
        )}

        {status === 'idle' && (
          <div style={{ color: '#6c757d' }}>⏸️ Waiting for you to upload or verify a file...</div>
        )}
      </div>
    </div>
  );
}

export default App;
